  function parseDate(v){if(!v) return null; const raw=String(v).trim(); if(/^\d{4}-\d{2}-\d{2}/.test(raw)) return new Date(raw.slice(0,10)+'T00:00:00'); const d=new Date(raw.replace(/(\d{1,2})\s([A-Za-z]{3})\s(\d{4})/,'$2 $1, $3')); return isNaN(d)?null:d;}
