  function calcCommissionFor(d,salesmanId,month){const target=(d.salesmanTargets||[]).find(t=>t.salesmanId===salesmanId && t.month===month)||{salesmanId,month,targetAmount:0,targetInvoices:0,commissionTiers:[{from:0,to:999,rate:0}],bonusOnTarget:0}; const invoices=(d.invoices||[]).filter(i=>isCompletedInvoice(i)&&i.salesmanId===salesmanId&&invMonth(i)===month); const actual=invoices.reduce((s,i)=>s+invTotal(i),0); const ach=num(target.targetAmount)>0?actual/num(target.targetAmount)*100:0; const tier=(target.commissionTiers||[]).slice().sort((a,b)=>num(b.from)-num(a.from)).find(t=>ach>=num(t.from))||{rate:0}; const commission=actual*num(tier.rate)/100; const bonus=ach>=100?num(target.bonusOnTarget):0; return {target,invoices,actual,ach,rate:num(tier.rate),commission,bonus,total:commission+bonus};}
