  function openSalesmanView(id){const d=migrateCore(); const sm=(d.salesmen||[]).find(s=>s.id===id); if(!sm) return; const month=$('#salesmenMonth')?.value||monthNow(); const c=calcCommissionFor(d,id,month); $('#historyModalName')&&( $('#historyModalName').textContent=sm.name+' — '+month ); if($('#historyStats')) $('#historyStats').innerHTML=`<div class="col-md-3"><div class="mini-stat"><span>Current Month Sales</span><h5>${money(c.actual)}</h5></div></div><div class="col-md-3"><div class="mini-stat"><span>Invoice Count</span><h5>${c.invoices.length}/${c.target.targetInvoices||0}</h5></div></div><div class="col-md-3"><div class="mini-stat"><span>Achievement</span><h5>${c.ach.toFixed(1)}%</h5></div></div><div class="col-md-3"><div class="mini-stat"><span>Total Payout</span><h5>${money(c.total)}</h5></div></div><div class="col-md-3"><div class="mini-stat"><span>Target Amount</span><h5>${money(c.target.targetAmount)}</h5></div></div><div class="col-md-3"><div class="mini-stat"><span>Commission Rate</span><h5>${c.rate}%</h5></div></div><div class="col-md-3"><div class="mini-stat"><span>Commission</span><h5>${money(c.commission)}</h5></div></div><div class="col-md-3"><div class="mini-stat"><span>Bonus</span><h5>${money(c.bonus)}</h5></div></div>`; if($('#historyTableBody')){const thead=$('#historyTableBody').closest('table')?.querySelector('thead tr'); if(thead) thead.innerHTML='<th>Invoice</th><th>Date</th><th>Customer</th><th>Status</th><th>Total</th><th>Paid</th><th>Balance</th>'; $('#historyTableBody').innerHTML=c.invoices.map(i=>`<tr><td>${esc(i.no||'')}</td><td>${esc(i.date||'')}</td><td>${esc(i.customer||'')}</td><td>${esc(i.status||'')}</td><td>${money(invTotal(i))}</td><td>${money(i.paid)}</td><td>${money(i.balance)}</td></tr>`).join('')||'<tr><td colspan="7" class="text-muted">No completed invoices assigned to this salesman for selected month.</td></tr>'; } showModal('#salesmanHistoryModal');}
  function initSalesmenFixed(){if(!$('#salesmenListBody')) return; if($('#addSalesmanModal')&&!$('#salesmanActive')) $('#salesmanJoinDate')?.closest('.col-md-6')?.insertAdjacentHTML('afterend','<div class="col-md-6"><label class="form-label">Active Status</label><select id="salesmanActive" class="form-select"><option value="true">Active</option><option value="false">Inactive</option></select></div>'); renderSalesmenFixed(); salesmenRefreshDropdowns(); ['salesmenMonth','targetMonth','performanceMonth','payoutMonth','salesmanBranchFilter'].forEach(id=>$('#'+id)?.addEventListener('change',renderSalesmenFixed)); document.addEventListener('click',e=>{const add=e.target.closest('[data-add-salesman]'); if(add){$('#editSalesmanId')&&( $('#editSalesmanId').value='' ); ['salesmanName','salesmanPhone','salesmanEmail'].forEach(id=>{$('#'+id)&&( $('#'+id).value='' );}); $('#salesmanBranch')&&( $('#salesmanBranch').value='Main Branch' ); $('#salesmanJoinDate')&&( $('#salesmanJoinDate').value=new Date().toISOString().slice(0,10) ); $('#salesmanActive')&&( $('#salesmanActive').value='true' ); $('#addSalesmanModal .modal-title')&&( $('#addSalesmanModal .modal-title').textContent='Add Salesman' ); showModal('#addSalesmanModal'); return;} const edit=e.target.closest('[data-edit-salesman]'); if(edit){e.preventDefault(); e.stopImmediatePropagation(); const s=(migrateCore().salesmen||[]).find(x=>x.id===edit.dataset.editSalesman); if(!s) return; $('#editSalesmanId').value=s.id; $('#salesmanName').value=s.name||''; $('#salesmanPhone').value=s.phone||''; $('#salesmanEmail').value=s.email||''; $('#salesmanBranch').value=s.branch||'Main Branch'; $('#salesmanJoinDate').value=s.joinDate||''; $('#salesmanActive')&&( $('#salesmanActive').value=String(s.active!==false) ); $('#addSalesmanModal .modal-title')&&( $('#addSalesmanModal .modal-title').textContent='Edit Salesman' ); showModal('#addSalesmanModal'); return;} const tog=e.target.closest('[data-toggle-salesman]'); if(tog){e.preventDefault(); e.stopImmediatePropagation(); const d=migrateCore(); const s=d.salesmen.find(x=>x.id===tog.dataset.toggleSalesman); if(!s) return; if(!confirm(`${s.active!==false?'Deactivate':'Activate'} ${s.name}?`)) return; s.active=s.active===false; save(d); renderSalesmenFixed(); salesmenRefreshDropdowns(); toast(`${s.name} ${s.active?'activated':'deactivated'}`); return;} const view=e.target.closest('[data-view-performance]'); if(view){e.preventDefault(); e.stopImmediatePropagation(); openSalesmanView(view.dataset.viewPerformance); return;} const target=e.target.closest('[data-set-target]'); if(target){e.preventDefault(); e.stopImmediatePropagation(); openTarget(target.dataset.setTarget); return;} const remove=e.target.closest('[data-remove-tier]'); if(remove){e.preventDefault(); e.stopImmediatePropagation(); remove.closest('tr')?.remove(); return;} const addTier=e.target.closest('#addTierBtn'); if(addTier){e.preventDefault(); e.stopImmediatePropagation(); addTierRow({from:0,to:999,rate:0}); return;} const saveSm=e.target.closest('#saveSalesmanBtn'); if(saveSm){e.preventDefault(); e.stopImmediatePropagation(); const d=migrateCore(); const id=$('#editSalesmanId')?.value; const name=$('#salesmanName')?.value.trim(); if(!name) return toast('Salesman name is required','warning'); if(id){const s=d.salesmen.find(x=>x.id===id); if(s){s.name=name; s.phone=$('#salesmanPhone')?.value||''; s.email=$('#salesmanEmail')?.value||''; s.branch=$('#salesmanBranch')?.value||'Main Branch'; s.joinDate=$('#salesmanJoinDate')?.value||''; s.active=$('#salesmanActive')?.value!=='false';}} else {const max=(d.salesmen||[]).reduce((m,s)=>Math.max(m,parseInt(String(s.id||'').replace(/\D/g,''),10)||0),0); d.salesmen.push({id:'SM'+String(max+1).padStart(3,'0'),name,phone:$('#salesmanPhone')?.value||'',email:$('#salesmanEmail')?.value||'',branch:$('#salesmanBranch')?.value||'Main Branch',joinDate:$('#salesmanJoinDate')?.value||new Date().toISOString().slice(0,10),active:$('#salesmanActive')?.value!=='false'});} save(d); hideModal('#addSalesmanModal'); renderSalesmenFixed(); salesmenRefreshDropdowns(); toast(id?'Salesman updated':'Salesman added'); return;} const saveT=e.target.closest('#saveTargetBtn'); if(saveT){e.preventDefault(); e.stopImmediatePropagation(); const d=migrateCore(); const rec={id:$('#targetId')?.value||nextNo('TGT',d.salesmanTargets),salesmanId:$('#targetSalesman')?.value,month:$('#targetMonthInput')?.value||monthNow(),targetAmount:num($('#targetAmount')?.value),targetInvoices:num($('#targetInvoices')?.value),commissionTiers:$$('#targetTierBody tr').map(r=>({from:num($('.tier-from',r)?.value),to:num($('.tier-to',r)?.value),rate:num($('.tier-rate',r)?.value)})),bonusOnTarget:num($('#bonusOnTarget')?.value),notes:$('#targetNotes')?.value||''}; if(!rec.salesmanId) return toast('Select a salesman','warning'); const idx=d.salesmanTargets.findIndex(t=>t.id===rec.id || (t.salesmanId===rec.salesmanId&&t.month===rec.month)); if(idx>=0)d.salesmanTargets[idx]=rec; else d.salesmanTargets.push(rec); save(d); hideModal('#targetModal'); renderSalesmenFixed(); toast('Target and commission tiers saved'); return;}},true);}

  function promotionTargetHtml(){return `<div class="col-md-6 promo-product-field"><label class="form-label">Product</label><select id="promoProduct" class="form-select"></select></div><div class="col-md-6 promo-category-field"><label class="form-label">Category</label><select id="promoCategory" class="form-select"></select></div><div class="col-md-6 promo-customer-group-field"><label class="form-label">Customer Group</label><select id="promoCustomerGroup" class="form-select"></select></div>`;}
  function enhancePromotionLayout(){if(!$('#promotionsBody')||$('#promoEditIndex')) return; const left=$('#promoName')?.closest('.cardx'); if(left) left.innerHTML=`<h5 class="cardx-title"><i class="bi bi-percent text-brand"></i> Add / Edit Promotion</h5><input type="hidden" id="promoEditIndex" value=""><div class="row g-2"><div class="col-md-6"><label class="form-label">Promotion name</label><input id="promoName" class="form-control" placeholder="Weekend Offer"></div><div class="col-md-6"><label class="form-label">Promotion code</label><input id="promoCode" class="form-control" placeholder="WEEKEND10"></div><div class="col-md-6"><label class="form-label">Promotion type</label><select id="promoType" class="form-select"><option>Product discount</option><option>Category discount</option><option>Customer group discount</option><option>Invoice discount</option><option>Buy X Get Y</option><option>Weekend offer</option><option>Date range offer</option></select></div><div class="col-md-6"><label class="form-label">Discount type</label><select id="promoDiscountType" class="form-select"><option>Percentage</option><option>Fixed amount</option></select></div><div class="col-md-6"><label class="form-label">Discount value</label><input id="promoValue" type="number" step="0.01" class="form-control" placeholder="10"></div><div class="col-md-6"><label class="form-label">Minimum invoice amount</label><input id="promoMinInvoice" type="number" step="0.01" class="form-control" placeholder="0"></div>${promotionTargetHtml()}<div class="col-md-6"><label class="form-label">Start date</label><input id="promoStartDate" type="date" class="form-control"></div><div class="col-md-6"><label class="form-label">End date</label><input id="promoEndDate" type="date" class="form-control"></div><div class="col-md-6"><label class="form-label">Status</label><select id="promoActive" class="form-select"><option value="true">Active</option><option value="false">Inactive</option></select></div><div class="col-12"><label class="form-label">Notes</label><textarea id="promoNotes" rows="2" class="form-control"></textarea></div><div class="col-12 d-flex gap-2"><button id="savePromoBtn" type="button" class="btn btn-brand flex-fill">Save Promotion</button><button id="resetPromoBtn" type="button" class="btn btn-soft">Reset</button></div></div><div class="soft-separator"></div><div id="coupon-demo"><h6 class="fw-bold">Coupon validation demo</h6><div class="input-group"><input id="couponInput" class="form-control" placeholder="Try HS10"><button id="validateCouponBtn" type="button" class="btn btn-soft">Validate</button></div><div id="couponResult" class="mt-2"></div></div>`; const table=$('#promotionsBody')?.closest('table'); const h=table?.querySelector('thead tr'); if(h) h.innerHTML='<th>Promotion</th><th>Code</th><th>Type</th><th>Discount</th><th>Dates</th><th>Status</th><th>Actions</th>';}
  function fillPromoOptions(){const d=migrateCore(); fillSelect('#promoProduct',(d.products||[]).filter(p=>p.deleted!==true).map(p=>p.sku||p.name),'Select product'); fillSelect('#promoCategory',unique((d.products||[]).map(p=>p.category)),'Select category'); fillSelect('#promoCustomerGroup',unique((d.customers||[]).map(c=>c.type||c.group||'Retail')),'Select group');}
  function updatePromoTargetVisibility(){const type=$('#promoType')?.value||''; $$('.promo-product-field').forEach(x=>x.style.display=type==='Product discount'?'':'none'); $$('.promo-category-field').forEach(x=>x.style.display=type==='Category discount'?'':'none'); $$('.promo-customer-group-field').forEach(x=>x.style.display=type==='Customer group discount'?'':'none');}
  function promoDiscountText(p){return `${p.discountType||(/%/.test(String(p.value))?'Percentage':'Fixed amount')} ${p.discountValue??String(p.value||'').replace(/[^0-9.]/g,'')}${(p.discountType||'').toLowerCase().includes('percentage')||String(p.value||'').includes('%')?'%':''}`;}
  function resetPromoForm(){['promoEditIndex','promoName','promoCode','promoValue','promoMinInvoice','promoStartDate','promoEndDate','promoNotes'].forEach(id=>{$('#'+id)&&( $('#'+id).value='' );}); $('#promoType')&&( $('#promoType').value='Weekend offer' ); $('#promoDiscountType')&&( $('#promoDiscountType').value='Percentage' ); $('#promoActive')&&( $('#promoActive').value='true' ); updatePromoTargetVisibility();}
  function renderPromotionsFixed(){if(!$('#promotionsBody')) return; const d=migrateCore(); const promos=(d.promotions||[]).filter(p=>p.deleted!==true); $('#promotionsBody').innerHTML=promos.map((p,i)=>`<tr><td><strong>${esc(p.name)}</strong><br><small class="text-muted">${esc(p.notes||'')}</small></td><td><span class="badge-soft badge-draft">${esc(p.code||'-')}</span></td><td>${esc(p.type||'')}</td><td>${esc(promoDiscountText(p))}</td><td>${esc(p.startDate||'-')} → ${esc(p.endDate||'-')}</td><td><span class="badge-soft ${p.active!==false?'badge-paid':'badge-danger-soft'}">${p.active!==false?'Active':'Inactive'}</span></td><td class="text-nowrap"><button class="btn btn-sm btn-soft" data-promo-edit="${i}">Edit</button> <button class="btn btn-sm ${p.active!==false?'btn-soft text-danger':'btn-brand'}" data-promo-toggle="${i}">${p.active!==false?'Deactivate':'Activate'}</button> <button class="btn btn-sm btn-soft text-danger" data-promo-delete="${i}">Delete</button></td></tr>`).join('')||'<tr><td colspan="7" class="text-muted">No promotions yet. Add your first promotion.</td></tr>'; $('#promoPreview')&&( $('#promoPreview').innerHTML=promos.filter(p=>p.active!==false).map(p=>`<div class="approval-rule mb-2"><strong>${esc(p.name)}</strong><br><small>${esc(p.code||'-')} • ${esc(p.type||'')} • ${esc(promoDiscountText(p))}</small></div>`).join('')||'<p class="text-muted mb-0">No active promotion.</p>' );}
  function savePromotionFromForm(){const d=migrateCore(); const promos=d.promotions=d.promotions||[]; const visible=promos.filter(p=>p.deleted!==true); const edit=String($('#promoEditIndex')?.value||''); const original=edit!==''?visible[Number(edit)]:null; const code=($('#promoCode')?.value||'').trim().toUpperCase(); const name=($('#promoName')?.value||'').trim(); if(!name) return toast('Promotion name is required','warning'); if(!code) return toast('Promotion code is required','warning'); if(promos.some(p=>p!==original && p.deleted!==true && String(p.code||'').toUpperCase()===code)) return toast('Duplicate promotion code blocked','danger'); const type=$('#promoType')?.value||'Weekend offer'; const rec={id:original?.id||nextNo('PROMO',promos),name,code,type,discountType:$('#promoDiscountType')?.value||'Percentage',discountValue:num($('#promoValue')?.value),value:($('#promoDiscountType')?.value==='Percentage'?num($('#promoValue')?.value)+'%':money($('#promoValue')?.value)),productSku:$('#promoProduct')?.value||'',category:$('#promoCategory')?.value||'',customerGroup:$('#promoCustomerGroup')?.value||'',minInvoiceAmount:num($('#promoMinInvoice')?.value),startDate:$('#promoStartDate')?.value||'',endDate:$('#promoEndDate')?.value||'',active:$('#promoActive')?.value!=='false',notes:$('#promoNotes')?.value||'',deleted:false}; if(original){const idx=promos.indexOf(original); promos[idx]=rec;} else promos.unshift(rec); save(d); resetPromoForm(); renderPromotionsFixed(); toast(original?'Promotion updated':'Promotion saved');}
  function initPromotionsFixed(){if(!$('#promotionsBody')) return; enhancePromotionLayout(); fillPromoOptions(); updatePromoTargetVisibility(); renderPromotionsFixed(); $('#promoType')?.addEventListener('change',updatePromoTargetVisibility); document.addEventListener('click',e=>{const saveBtn=e.target.closest('#savePromoBtn'); if(saveBtn){e.preventDefault(); e.stopImmediatePropagation(); savePromotionFromForm(); return;} const reset=e.target.closest('#resetPromoBtn'); if(reset){e.preventDefault(); resetPromoForm(); return;} const edit=e.target.closest('[data-promo-edit]'); if(edit){e.preventDefault(); e.stopImmediatePropagation(); const p=(migrateCore().promotions||[]).filter(x=>x.deleted!==true)[Number(edit.dataset.promoEdit)]; if(!p) return; $('#promoEditIndex').value=edit.dataset.promoEdit; $('#promoName').value=p.name||''; $('#promoCode').value=p.code||''; $('#promoType').value=p.type||'Weekend offer'; $('#promoDiscountType').value=p.discountType||'Percentage'; $('#promoValue').value=p.discountValue??String(p.value||'').replace(/[^0-9.]/g,''); $('#promoProduct').value=p.productSku||''; $('#promoCategory').value=p.category||''; $('#promoCustomerGroup').value=p.customerGroup||''; $('#promoMinInvoice').value=p.minInvoiceAmount||0; $('#promoStartDate').value=p.startDate||''; $('#promoEndDate').value=p.endDate||''; $('#promoActive').value=String(p.active!==false); $('#promoNotes').value=p.notes||''; updatePromoTargetVisibility(); toast('Promotion loaded for editing'); return;} const tog=e.target.closest('[data-promo-toggle]'); if(tog){e.preventDefault(); e.stopImmediatePropagation(); const d=migrateCore(); const p=(d.promotions||[]).filter(x=>x.deleted!==true)[Number(tog.dataset.promoToggle)]; if(!p) return; p.active=p.active===false; save(d); renderPromotionsFixed(); toast('Promotion status updated'); return;} const del=e.target.closest('[data-promo-delete]'); if(del){e.preventDefault(); e.stopImmediatePropagation(); const d=migrateCore(); const p=(d.promotions||[]).filter(x=>x.deleted!==true)[Number(del.dataset.promoDelete)]; if(!p) return; if(!confirm('Delete this promotion?')) return; p.deleted=true; save(d); renderPromotionsFixed(); toast('Promotion deleted'); return;} const val=e.target.closest('#validateCouponBtn'); if(val){e.preventDefault(); e.stopImmediatePropagation(); const code=($('#couponInput')?.value||'').trim().toUpperCase(); const today=new Date(); const p=(migrateCore().promotions||[]).find(x=>x.deleted!==true&&x.active!==false&&String(x.code||'').toUpperCase()===code&&(!x.startDate||parseDate(x.startDate)<=today)&&(!x.endDate||parseDate(x.endDate)>=new Date(today.toDateString()))); $('#couponResult').innerHTML=p?`<div class="alert alert-success mb-0">Coupon valid: ${esc(p.name)} (${esc(promoDiscountText(p))})</div>`:'<div class="alert alert-danger mb-0">Invalid, expired or inactive coupon.</div>'; return;}},true);}

